import React, { useState, useEffect } from 'react';
import { Globe, ArrowUpRight, Zap } from 'lucide-react';
// Import the hook directly from the context file
import { useAuth } from '../context/AuthContext'; 

const LiveMarket = () => {
  // Use the hook to get the token
  const { token } = useAuth(); 
  const [connectionStatus, setConnectionStatus] = useState('CONNECTING');

  useEffect(() => {
    if (!token) return;

    // Connect to the WebSocket Pulse route
    const socket = new WebSocket(`ws://localhost:8000/ws/pulse?token=${token}`);
    
    socket.onopen = () => setConnectionStatus('STABLE');
    socket.onerror = () => setConnectionStatus('ERROR');
    socket.onclose = () => setConnectionStatus('OFFLINE');

    return () => socket.close();
  }, [token]);

  return (
    <div className="reveal-node" style={{ padding: '2.5rem', maxWidth: '1200px', margin: '0 auto' }}>
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '2rem' }}>
        <h2 style={{ display: 'flex', alignItems: 'center', gap: '10px', color: 'var(--text-primary)' }}>
          <Globe size={20} color="var(--accent-primary)" /> LIVE_MARKET_PULSE
        </h2>
        <div style={{ 
          color: connectionStatus === 'STABLE' ? 'var(--accent-primary)' : '#ef4444', 
          fontSize: '0.6rem', 
          fontWeight: 800,
          textTransform: 'uppercase'
        }}>
          NODE_STATUS: {connectionStatus}
        </div>
      </div>

      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(220px, 1fr))', gap: '1rem' }}>
        {['RELIANCE', 'TCS', 'HDFCBANK', 'INFY'].map((ticker) => (
          <div key={ticker} style={{ padding: '1.5rem', background: 'var(--surface-glass)', border: '1px solid var(--surface-border)', borderRadius: '16px' }}>
            <div style={{ display: 'flex', justifyContent: 'space-between' }}>
              <span style={{ fontWeight: 800 }}>{ticker}</span>
              <Zap size={14} color="var(--accent-primary)" />
            </div>
            <div style={{ fontSize: '1.2rem', fontWeight: 900, margin: '10px 0' }}>
               ₹{(2400 + Math.random() * 100).toFixed(2)}
            </div>
            <div style={{ fontSize: '0.6rem', color: 'var(--accent-primary)', display: 'flex', alignItems: 'center' }}>
              <ArrowUpRight size={10} /> +0.85%
            </div>
          </div>
        ))}
      </div>
    </div>
  );
};

export default LiveMarket;
